enum AppErrorCode{networkUnavailable,authRequired,remoteNotFound,conflictDetected,validationFailed,unsupportedSchema,operationNotImplemented,unknown}extension AppErrorCodeLabel on AppErrorCode{String get code=>name;String get message{switch(this){case AppErrorCode.networkUnavailable:return 'Network is unavailable.';case AppErrorCode.authRequired:return 'Authentication is required.';case AppErrorCode.remoteNotFound:return 'Remote resource was not found.';case AppErrorCode.conflictDetected:return 'A sync conflict was detected.';case AppErrorCode.validationFailed:return 'Validation failed.';case AppErrorCode.unsupportedSchema:return 'Schema version is unsupported.';case AppErrorCode.operationNotImplemented:return 'Operation is not implemented yet.';case AppErrorCode.unknown:return 'Unknown error.';}}}
